/// MolmoAct2 Vision Transformer encoder.
///
/// 27-layer bidirectional ViT, 378×378 input, 14px patches → 729 patches.
/// float32 attention, gelu_pytorch_tanh FFN, LayerNorm (not RMSNorm).
/// Extracts intermediate layer outputs at configured indices, returns their
/// concatenation as the adapter input.
///
/// Weight naming convention in the .knot file:
///   vit_patch_emb_weight       [hidden, patch_dim]   (patch_dim = 14*14*3 = 588)
///   vit_patch_emb_bias         [hidden]
///   vit_pos_emb_weight         [n_patches, hidden]
///   vit_pre_ln_weight          [hidden]
///   vit_pre_ln_bias            [hidden]
///   vit_blk_{i}_ln1_weight     [hidden]
///   vit_blk_{i}_ln1_bias       [hidden]
///   vit_blk_{i}_attn_q_weight  [hidden, hidden]
///   vit_blk_{i}_attn_q_bias   [hidden]
///   vit_blk_{i}_attn_k_weight  [hidden, hidden]
///   vit_blk_{i}_attn_k_bias   [hidden]
///   vit_blk_{i}_attn_v_weight  [hidden, hidden]
///   vit_blk_{i}_attn_v_bias   [hidden]
///   vit_blk_{i}_attn_out_weight [hidden, hidden]
///   vit_blk_{i}_attn_out_bias  [hidden]
///   vit_blk_{i}_ln2_weight     [hidden]
///   vit_blk_{i}_ln2_bias       [hidden]
///   vit_blk_{i}_mlp_fc1_weight [intermediate, hidden]
///   vit_blk_{i}_mlp_fc1_bias   [intermediate]
///   vit_blk_{i}_mlp_fc2_weight [hidden, intermediate]
///   vit_blk_{i}_mlp_fc2_bias   [hidden]
use std::sync::Arc;

use crate::loader::WeightBackend;
use crate::math::{
    accumulate_weighted, dot_product, gelu_inplace, layer_norm, mat_vec_f32, softmax,
};
use crate::model_molmoact2_config::MolmoAct2VitConfig;

/// Pre-resolved tensor names for a single ViT block.
struct VitBlockNames {
    ln1_w: String,
    ln1_b: String,
    attn_q_w: String,
    attn_q_b: String,
    attn_k_w: String,
    attn_k_b: String,
    attn_v_w: String,
    attn_v_b: String,
    attn_out_w: String,
    attn_out_b: String,
    ln2_w: String,
    ln2_b: String,
    mlp_fc1_w: String,
    mlp_fc1_b: String,
    mlp_fc2_w: String,
    mlp_fc2_b: String,
}

impl VitBlockNames {
    fn new(i: usize) -> Self {
        Self {
            ln1_w: format!("vit_blk_{i}_ln1_weight"),
            ln1_b: format!("vit_blk_{i}_ln1_bias"),
            attn_q_w: format!("vit_blk_{i}_attn_q_weight"),
            attn_q_b: format!("vit_blk_{i}_attn_q_bias"),
            attn_k_w: format!("vit_blk_{i}_attn_k_weight"),
            attn_k_b: format!("vit_blk_{i}_attn_k_bias"),
            attn_v_w: format!("vit_blk_{i}_attn_v_weight"),
            attn_v_b: format!("vit_blk_{i}_attn_v_bias"),
            attn_out_w: format!("vit_blk_{i}_attn_out_weight"),
            attn_out_b: format!("vit_blk_{i}_attn_out_bias"),
            ln2_w: format!("vit_blk_{i}_ln2_weight"),
            ln2_b: format!("vit_blk_{i}_ln2_bias"),
            mlp_fc1_w: format!("vit_blk_{i}_mlp_fc1_weight"),
            mlp_fc1_b: format!("vit_blk_{i}_mlp_fc1_bias"),
            mlp_fc2_w: format!("vit_blk_{i}_mlp_fc2_weight"),
            mlp_fc2_b: format!("vit_blk_{i}_mlp_fc2_bias"),
        }
    }
}

pub struct MolmoAct2ViT {
    pub config: MolmoAct2VitConfig,
    backend: Arc<dyn WeightBackend>,
    blocks: Vec<VitBlockNames>,
    /// Sorted layer indices at which we capture intermediate hidden states.
    extract_layers: Vec<usize>,
    // Scratch buffers (seq = n_patches throughout).
    x: Vec<f32>,        // [seq * hidden]
    xb: Vec<f32>,       // [seq * hidden]
    q_buf: Vec<f32>,    // [seq * hidden]
    k_buf: Vec<f32>,    // [seq * hidden]
    v_buf: Vec<f32>,    // [seq * hidden]
    attn_out: Vec<f32>, // [seq * hidden]
    mlp_buf: Vec<f32>,  // [seq * intermediate]
}

impl MolmoAct2ViT {
    pub fn new(config: MolmoAct2VitConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let n = config.n_patches();
        let h = config.hidden_size;
        let inter = config.intermediate_size;
        let extract_layers = config.extract_layer_indices();
        let blocks = (0..config.num_hidden_layers)
            .map(VitBlockNames::new)
            .collect();
        Self {
            blocks,
            extract_layers,
            x: vec![0.0; n * h],
            xb: vec![0.0; n * h],
            q_buf: vec![0.0; n * h],
            k_buf: vec![0.0; n * h],
            v_buf: vec![0.0; n * h],
            attn_out: vec![0.0; n * h],
            mlp_buf: vec![0.0; n * inter],
            config,
            backend,
        }
    }

    /// Encode a single image.
    ///
    /// `pixels` must be a flat f32 array of shape [C=3, H=378, W=378] in
    /// channel-first normalized form (mean/std normalization applied by caller).
    ///
    /// Returns the concatenation of the extracted intermediate hidden states:
    /// shape [n_patches, n_extract_layers * hidden_size].
    pub fn forward(&mut self, pixels: &[f32]) -> Result<Vec<f32>, String> {
        let n = self.config.n_patches();
        let h = self.config.hidden_size;
        let patch_dim = self.config.patch_dim();
        let layer_norm_eps = self.config.layer_norm_eps;
        let num_hidden_layers = self.config.num_hidden_layers;

        // 1. Patch embedding: project each patch from pixel space to hidden_size.
        self.patch_embed(pixels, n, h, patch_dim)?;

        // 2. Add learnable positional embeddings (row-wise).
        {
            let pos_bytes = self
                .backend
                .fetch_tensor("vit_pos_emb_weight")
                .map_err(|e| format!("vit_pos_emb_weight: {e}"))?;
            let pos = bytes_to_f32(&pos_bytes);
            for t in 0..n {
                let row = &pos[t * h..(t + 1) * h];
                let x_row = &mut self.x[t * h..(t + 1) * h];
                for i in 0..h {
                    x_row[i] += row[i];
                }
            }
        }

        // 3. Optional pre-encoder LayerNorm (Molmo uses one before the blocks).
        if self.backend.has_tensor("vit_pre_ln_weight") {
            let w_bytes = self
                .backend
                .fetch_tensor("vit_pre_ln_weight")
                .map_err(|e| format!("vit_pre_ln_weight: {e}"))?;
            let b_bytes = self
                .backend
                .fetch_tensor("vit_pre_ln_bias")
                .map_err(|e| format!("vit_pre_ln_bias: {e}"))?;
            let w = bytes_to_f32(&w_bytes);
            let b = bytes_to_f32(&b_bytes);
            let eps = layer_norm_eps;
            for t in 0..n {
                let row = self.x[t * h..(t + 1) * h].to_vec();
                layer_norm(&mut self.xb[t * h..(t + 1) * h], &row, w, b, eps);
            }
            self.x.copy_from_slice(&self.xb);
        }

        // 4. Transformer blocks — collect extractions.
        let n_extract = self.extract_layers.len();
        let mut extracted: Vec<Vec<f32>> = Vec::with_capacity(n_extract);

        for l in 0..num_hidden_layers {
            self.encoder_block(l, n)?;
            if self.extract_layers.contains(&l) {
                extracted.push(self.x[..n * h].to_vec());
            }
        }

        // 5. Concatenate extracted layers along the feature dimension.
        // Output: [n_patches, n_extract_layers * hidden_size]
        let out_dim = n_extract * h;
        let mut out = vec![0.0f32; n * out_dim];
        for t in 0..n {
            for (ei, extracted_layer) in extracted.iter().enumerate() {
                let src = &extracted_layer[t * h..(t + 1) * h];
                let dst_off = t * out_dim + ei * h;
                out[dst_off..dst_off + h].copy_from_slice(src);
            }
        }

        Ok(out)
    }

    /// Project patches from pixel space into the hidden dimension.
    fn patch_embed(
        &mut self,
        pixels: &[f32],
        _n_patches: usize,
        hidden: usize,
        patch_dim: usize,
    ) -> Result<(), String> {
        let cfg = &self.config;
        let ps = cfg.patch_size;
        let w_img = cfg.image_size;
        let grid = w_img / ps;

        let w_bytes = self
            .backend
            .fetch_tensor("vit_patch_emb_weight")
            .map_err(|e| format!("vit_patch_emb_weight: {e}"))?;
        let b_bytes = self
            .backend
            .fetch_tensor("vit_patch_emb_bias")
            .map_err(|e| format!("vit_patch_emb_bias: {e}"))?;
        let wf = bytes_to_f32(&w_bytes);
        let bf = bytes_to_f32(&b_bytes);

        // Extract patches in raster order (CHW input).
        let mut patch_flat = vec![0.0f32; patch_dim];
        for py in 0..grid {
            for px in 0..grid {
                let patch_idx = py * grid + px;
                // CHW: each channel C, then rows, then cols.
                for c in 0..3usize {
                    for dy in 0..ps {
                        for dx in 0..ps {
                            let src_idx =
                                c * (w_img * w_img) + (py * ps + dy) * w_img + (px * ps + dx);
                            let dst_idx = c * ps * ps + dy * ps + dx;
                            patch_flat[dst_idx] = pixels[src_idx];
                        }
                    }
                }
                let dst = &mut self.x[patch_idx * hidden..(patch_idx + 1) * hidden];
                mat_vec_f32(dst, &patch_flat, wf, hidden, patch_dim);
                for i in 0..hidden {
                    dst[i] += bf[i];
                }
            }
        }
        Ok(())
    }

    /// Single transformer encoder block (bidirectional, no causal mask, no RoPE).
    fn encoder_block(&mut self, l: usize, seq: usize) -> Result<(), String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let inter = cfg.intermediate_size;
        let n_heads = cfg.num_attention_heads;
        let head_dim = cfg.head_dim();
        let eps = cfg.layer_norm_eps;
        let bn = &self.blocks[l];
        let scale = 1.0 / (head_dim as f32).sqrt();

        // Pre-attn LayerNorm → xb
        {
            let w_b = self
                .backend
                .fetch_tensor(&bn.ln1_w)
                .map_err(|e| format!("layer {l} ln1_w: {e}"))?;
            let b_b = self
                .backend
                .fetch_tensor(&bn.ln1_b)
                .map_err(|e| format!("layer {l} ln1_b: {e}"))?;
            let w = bytes_to_f32(&w_b);
            let b = bytes_to_f32(&b_b);
            for t in 0..seq {
                let src = self.x[t * h..(t + 1) * h].to_vec();
                layer_norm(&mut self.xb[t * h..(t + 1) * h], &src, w, b, eps);
            }
        }

        // Q/K/V projections + biases (batched over all tokens).
        self.project_qkv(l, seq, h)?;

        // Bidirectional multi-head attention.
        self.attn_out[..seq * h].fill(0.0);
        {
            let mut scores = vec![0.0f32; seq];
            for t_out in 0..seq {
                for head in 0..n_heads {
                    let q_off = t_out * h + head * head_dim;
                    let q_head = &self.q_buf[q_off..q_off + head_dim];

                    for t_src in 0..seq {
                        let k_off = t_src * h + head * head_dim;
                        scores[t_src] =
                            dot_product(q_head, &self.k_buf[k_off..k_off + head_dim]) * scale;
                    }
                    softmax(&mut scores[..seq]);

                    let out_off = t_out * h + head * head_dim;
                    let head_out = &mut self.attn_out[out_off..out_off + head_dim];
                    head_out.fill(0.0);
                    for t_src in 0..seq {
                        let v_off = t_src * h + head * head_dim;
                        accumulate_weighted(
                            head_out,
                            &self.v_buf[v_off..v_off + head_dim],
                            scores[t_src],
                        );
                    }
                }
            }
        }

        // O-projection + bias → residual add.
        {
            let w_b = self
                .backend
                .fetch_tensor(&self.blocks[l].attn_out_w)
                .map_err(|e| format!("layer {l} attn_out_w: {e}"))?;
            let b_b = self
                .backend
                .fetch_tensor(&self.blocks[l].attn_out_b)
                .map_err(|e| format!("layer {l} attn_out_b: {e}"))?;
            let wf = bytes_to_f32(&w_b);
            let bf = bytes_to_f32(&b_b);
            // Reuse xb as O-proj output.
            for t in 0..seq {
                let inp = &self.attn_out[t * h..(t + 1) * h];
                mat_vec_f32(&mut self.xb[t * h..(t + 1) * h], inp, wf, h, h);
                for i in 0..h {
                    self.x[t * h + i] += self.xb[t * h + i] + bf[i];
                }
            }
        }

        // Pre-MLP LayerNorm → xb
        {
            let w_b = self
                .backend
                .fetch_tensor(&self.blocks[l].ln2_w)
                .map_err(|e| format!("layer {l} ln2_w: {e}"))?;
            let b_b = self
                .backend
                .fetch_tensor(&self.blocks[l].ln2_b)
                .map_err(|e| format!("layer {l} ln2_b: {e}"))?;
            let w = bytes_to_f32(&w_b);
            let b = bytes_to_f32(&b_b);
            for t in 0..seq {
                let src = self.x[t * h..(t + 1) * h].to_vec();
                layer_norm(&mut self.xb[t * h..(t + 1) * h], &src, w, b, eps);
            }
        }

        // MLP: fc1 + GELU → fc2 → residual add.
        {
            let fc1_w_b = self
                .backend
                .fetch_tensor(&self.blocks[l].mlp_fc1_w)
                .map_err(|e| format!("layer {l} mlp_fc1_w: {e}"))?;
            let fc1_b_b = self
                .backend
                .fetch_tensor(&self.blocks[l].mlp_fc1_b)
                .map_err(|e| format!("layer {l} mlp_fc1_b: {e}"))?;
            let fc2_w_b = self
                .backend
                .fetch_tensor(&self.blocks[l].mlp_fc2_w)
                .map_err(|e| format!("layer {l} mlp_fc2_w: {e}"))?;
            let fc2_b_b = self
                .backend
                .fetch_tensor(&self.blocks[l].mlp_fc2_b)
                .map_err(|e| format!("layer {l} mlp_fc2_b: {e}"))?;
            let fc1_w = bytes_to_f32(&fc1_w_b);
            let fc1_b = bytes_to_f32(&fc1_b_b);
            let fc2_w = bytes_to_f32(&fc2_w_b);
            let fc2_b = bytes_to_f32(&fc2_b_b);

            for t in 0..seq {
                let inp = &self.xb[t * h..(t + 1) * h];
                let mid = &mut self.mlp_buf[t * inter..(t + 1) * inter];
                mat_vec_f32(mid, inp, fc1_w, inter, h);
                for i in 0..inter {
                    mid[i] += fc1_b[i];
                }
                gelu_inplace(mid);

                let out = &mut self.xb[t * h..(t + 1) * h];
                mat_vec_f32(
                    out,
                    &self.mlp_buf[t * inter..(t + 1) * inter],
                    fc2_w,
                    h,
                    inter,
                );
                for i in 0..h {
                    self.x[t * h + i] += out[i] + fc2_b[i];
                }
            }
        }

        Ok(())
    }

    /// Project xb into Q, K, V buffers (batched over all tokens in the sequence).
    fn project_qkv(&mut self, l: usize, seq: usize, h: usize) -> Result<(), String> {
        let bn = &self.blocks[l];

        let q_w_b = self
            .backend
            .fetch_tensor(&bn.attn_q_w)
            .map_err(|e| format!("layer {l} attn_q_w: {e}"))?;
        let q_b_b = self
            .backend
            .fetch_tensor(&bn.attn_q_b)
            .map_err(|e| format!("layer {l} attn_q_b: {e}"))?;
        let k_w_b = self
            .backend
            .fetch_tensor(&bn.attn_k_w)
            .map_err(|e| format!("layer {l} attn_k_w: {e}"))?;
        let k_b_b = self
            .backend
            .fetch_tensor(&bn.attn_k_b)
            .map_err(|e| format!("layer {l} attn_k_b: {e}"))?;
        let v_w_b = self
            .backend
            .fetch_tensor(&bn.attn_v_w)
            .map_err(|e| format!("layer {l} attn_v_w: {e}"))?;
        let v_b_b = self
            .backend
            .fetch_tensor(&bn.attn_v_b)
            .map_err(|e| format!("layer {l} attn_v_b: {e}"))?;

        let q_w = bytes_to_f32(&q_w_b);
        let q_b = bytes_to_f32(&q_b_b);
        let k_w = bytes_to_f32(&k_w_b);
        let k_b = bytes_to_f32(&k_b_b);
        let v_w = bytes_to_f32(&v_w_b);
        let v_b = bytes_to_f32(&v_b_b);

        for t in 0..seq {
            let inp = &self.xb[t * h..(t + 1) * h];

            let q_out = &mut self.q_buf[t * h..(t + 1) * h];
            mat_vec_f32(q_out, inp, q_w, h, h);
            for i in 0..h {
                q_out[i] += q_b[i];
            }

            let k_out = &mut self.k_buf[t * h..(t + 1) * h];
            mat_vec_f32(k_out, inp, k_w, h, h);
            for i in 0..h {
                k_out[i] += k_b[i];
            }

            let v_out = &mut self.v_buf[t * h..(t + 1) * h];
            mat_vec_f32(v_out, inp, v_w, h, h);
            for i in 0..h {
                v_out[i] += v_b[i];
            }
        }
        Ok(())
    }
}

#[inline]
fn bytes_to_f32(bytes: &[u8]) -> &[f32] {
    assert!(bytes.len().is_multiple_of(4));
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}
